use master
go

IF EXISTS (SELECT * FROM sys.databases WHERE name = 'RescuePets')
BEGIN
    DROP DATABASE RescuePets;
END
GO

CREATE DATABASE RescuePets
go

USE RescuePets
go

--CREATE TABLES: GENDER, [LOCATION], CLIENT, PET TYPE, PET BREED, PET, PET_BREED, IMAGE, number, post, donate 10 tables
--GENDER TABLE
CREATE TABLE Gender (
	Gender_ID INT IDENTITY (1,1) PRIMARY KEY NOT NULL,
	Gender_Name VARCHAR(6)	
)
go

--LOCATION TABLE BY PROVINCE
CREATE TABLE [Location](
	Location_ID INT IDENTITY (1,1) PRIMARY KEY NOT NULL,
	Location_Name VARCHAR(30) NOT NULL
)
Go

--PET TYPE
CREATE TABLE Pet_Type(
	[Type_ID] INT IDENTITY (1,1) PRIMARY KEY NOT NULL,
	[Type_Name] VARCHAR(30) NOT NULL
)
Go

--PET BREED TABLE
CREATE TABLE Pet_Breed (
	Breed_ID INT IDENTITY (1,1) PRIMARY KEY NOT NULL,
	Breed_Name VARCHAR(30) NOT NULL,
	[Type_ID] INT,
	FOREIGN KEY ([Type_ID]) REFERENCES Pet_Type([Type_ID])
)
Go

--PET 
CREATE TABLE Pet (
	Pet_ID INT IDENTITY (1,1) PRIMARY KEY NOT NULL,
	Pet_Name VARCHAR(20),
	[Pet_Age] VARCHAR(20),
	Pet_Weight VARCHAR(6),
	Pet_Long_Description VARCHAR(900),
	Pet_Short_Description VARCHAR(300),
	Gender_ID INT,
	FOREIGN KEY (Gender_ID) REFERENCES Gender (Gender_ID),
	Breed_ID INT,
	FOREIGN KEY (Breed_ID) REFERENCES Pet_Breed(Breed_ID),
	[Location_ID] INT,
	FOREIGN KEY ([Location_ID]) REFERENCES [Location]([Location_ID])
)
Go

--Image table
CREATE TABLE Pet_Image (
	Image_ID int IDENTITY (1,1) PRIMARY KEY NOT NULL,
	Pet_ID int NOT NULL,
	[B64Image] [nvarchar](max) NOT NULL,
	FOREIGN KEY (Pet_ID) REFERENCES Pet(Pet_ID)
)
GO

--USER TABLE
CREATE TABLE [User](
	[User_ID] INT IDENTITY (1,1) PRIMARY KEY NOT NULL,
	[User_Name] VARCHAR (20) NOT NULL
)
Go

--NUMBER TABLE
CREATE TABLE Number(
	Number_ID INT IDENTITY (1,1) PRIMARY KEY NOT NULL,
	Number INT NOT NULL,
	[User_ID] INT NOT NULL,
	FOREIGN KEY ([User_ID]) REFERENCES [User]([User_ID])
)
GO

--ADOPT TABLE
CREATE TABLE Adopted (
	Adopt_ID INT IDENTITY (1,1) PRIMARY KEY NOT NULL,
	[User_ID] INT NOT NULL,
	FOREIGN KEY ([User_ID]) REFERENCES [User]([User_ID]),
	Pet_ID INT NOT NULL,
	FOREIGN KEY (Pet_ID) REFERENCES Pet(Pet_ID)
)
GO

--POSTER TABLE
CREATE TABLE Post (
	Post_ID INT IDENTITY (1,1) PRIMARY KEY NOT NULL,
	[User_ID] INT NOT NULL,
	FOREIGN KEY ([User_ID]) REFERENCES [User]([User_ID]),
	Pet_ID INT NOT NULL,
	FOREIGN KEY (Pet_ID) REFERENCES Pet(Pet_ID)
)
Go

--DONATE TABLE
CREATE TABLE Donate (
	Donate_ID INT IDENTITY (1,1) PRIMARY KEY NOT NULL,
	[User_ID] INT NOT NULL,
	FOREIGN KEY ([User_ID]) REFERENCES [User]([User_ID]),
	Amount INT NOT NULL
)
Go

