-- INSERT INTO PET TABLE
-- for cats
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (1, 1, 1, 'Biscuit', '1 months', '12kg', 'A tiny, utterly fluffy white kitten ready for adventure.', 'Meet Biscuit, a playful one-month-old Turkish Angora kitten. For her small size, she has boundless energy and loves chasing string toys. She’s a little cloud of white fluff just waiting for cuddles and her forever home. She is already litter trained and ready to be spoiled!')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (1, 2, 3, 'Noodle', '2 years', '30kg', 'A magnificent, affectionate Turkish Angora with a huge heart.', 'Noodle is a handsome two-year-old male Turkish Angora. Weighing in at 30kg, he is a substantial cat, but all of it is pure love. He’s a gentleman who adores basking in sunbeams and will follow you around the house just in case you happen to have a treat. His purr is legendary!')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight,Pet_Short_Description, Pet_Long_Description) 
VALUES (2, 1, 6, 'Nugget', '5 months', '17kg', 'A zesty ginger tabby girl with a vibrant personality.', 'Five-month-old Nugget is a charming female domestic shorthair with classic ginger tabby markings. This little firecracker is a purr-machine who loves to explore and play. She’s looking for an active family that can keep up with her fun, zesty personality and provide endless scratches.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight,Pet_Short_Description, Pet_Long_Description) 
VALUES (2, 2, 2, 'Sunshine', '6 months', '12kg', 'Pure happiness in cat form—a truly sweet and gentle boy.', 'Sunshine, a six-month-old male domestic shorthair, lives up to his name. He is a sweet, gentle cat with a soft coat and an even softer disposition. He’s not a fan of loud noises, preferring quiet playtime and long naps on a soft blanket. He will undoubtedly brighten up any loving home he joins.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (3, 1, 9, 'Google', '3 years', '25kg', 'A sleek, black, and highly intelligent Bombay cat.', 'Three-year-old Google is as clever as his name suggests. This female Bombay cat has a stunning, black, patent-leather coat and a highly inquisitive nature. She will happily learn to fetch toys and is known for solving food puzzles in record time. She needs a stimulating environment to keep her sharp mind engaged.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (3, 2, 4, 'Nimbus', '3 years', '27kg', 'A handsome "cloudy" black cat always ready for a nap.', 'Nimbus is a three-year-old male Bombay. While he shares the breed’s sleek black coat, his personality is decidedly mellow. He is an exceptionally calm and easy-going cat who views any lap as a perfect napping spot. If you’re looking for a quiet, comforting companion, Nimbus is ready to drift into your life.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (4, 1, 4, 'Zephyr', '10 months', '20kg', 'A fluffy Siberian who is a little winter wonder.', 'Meet Zephyr, a gorgeous ten-month-old female Siberian. She boasts a thick, luxurious coat that is ready for cool weather. She’s a playful cat who loves chasing mice toys and batting at feathers. She would thrive in a home where she can be admired and kept busy with plenty of engaging play.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (4, 2, 7, 'Peach', '5 months', '15kg', 'A sweet and gentle male Siberian who loves to be groomed.', 'Peach is a stunning five-month-old male Siberian cat. Despite his young age, he’s incredibly gentle and patient. He adores the attention that comes with being brushed and will purr the whole time. He’s looking for a family who appreciates a calm, fluffy presence in their home.')

-- for hamster
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (5, 1, 4, 'Pudding', '2 months', '20g', 'An adorable cheek pouch filler with a quiet, burrowing habit.', 'Pudding is the sweetest two-month-old female Syrian Hamster you’ll ever meet. She has the classic hamster habit of filling her cheek pouches! She’s surprisingly quiet, preferring to spend her time burrowing in her substrate and building intricate little nests. She’s a gentle companion ready for a calm home.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (5, 2, 1, 'Muffin', '6 months', '41g', 'A big, friendly Syrian who is dedicated to his wheel.', 'Muffin is a chonky six-month-old male Syrian Hamster. He loves his food, especially sunflower seeds, but he balances it out by putting in serious miles on his exercise wheel every night. He’s friendly, easy to handle, and would make an excellent pet for an older child or first-time small animal owner.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (6, 2, 3, 'Honey', '7 months', '15g', 'The smallest ball of fluff, a quick and curious explorer.', 'Honey is a seven-month-old male Dwarf Winter White Hamster. He is a truly tiny creature, but what he lacks in size, he makes up for in curiosity! He’s quick, active, and loves to climb on his cage accessories. He needs a secure habitat and an owner who enjoys watching a tiny dynamo in action.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (6, 2, 6, 'Cupcake', '10 months', '30g', 'A tiny, sweet Dwarf—the perfect beginner pet.', 'Cupcake is a ten-month-old male Dwarf Winter White Hamster. This adorable little guy is a wonderful bundle of joy and a great introductory pet. He’s relatively calm for a dwarf and is happy to be gently handled. His sweet nature makes him an ideal companion for a responsible beginner pet owner.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (7, 1, 7, 'Jellybean', '8 months', '23g', 'A zippy little Roborovski—tiny but incredibly fast!', 'Tiny but mighty! Eight-month-old female Roborovski Hamster Jellybean is the fastest little runner in our care. She’s a shy species, best suited for an owner who prefers to watch their pet’s antics rather than handle them frequently. Her high-speed running is a fantastic spectacle!')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (7, 2, 9, 'Waffles', '3 years', '45g', 'An experienced, calm three-year-old who enjoys quiet evenings.', 'Waffles is a very mature, three-year-old male Roborovski Hamster. At 45g, he’s a bit of a gentle giant for his species. He has mellowed out in his senior years and enjoys quiet, peaceful evenings. He is looking for a relaxed home to spend his golden retirement years.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (8, 1, 2, 'Cinnamon', '2 months', '25g', 'A long, slender, and sweet Chinese hamster who loves tunnels.', 'Cinnamon is a shy but curious two-month-old female Chinese Hamster. Her long, slender body is perfect for burrowing and exploring tunnels. Once she gets to know you, she’s sweet and happy to take treats right from your hand. She needs a quiet environment to feel secure.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (8, 2, 2, 'Blossom', '3 years', '34g', 'A very mature male Chinese hamster ready for a loving home.', 'Blossom is a three-year-old male Chinese Hamster. He is an experienced small animal and very set in his routine. He’s a wonderful, low-maintenance pet who enjoys his food and long naps. He’d be perfect for someone looking for a calm, seasoned small companion.')

-- for Snake
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (9, 2, 7, 'Knob', '5 years', '5g', 'A very tiny, very old Rat Snake needing an experienced owner.', 'Knob is a small but seasoned five-year-old male Rat Snake. At just 5 grams, he’s on the smaller side and needs an owner with experience in caring for mature, small reptiles. He’s a calm creature who requires a quiet, stable enclosure and consistent handling to remain settled.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (9, 1, 3, 'Snazzy', '2 years', '2.7kg', 'A gorgeous, beautifully patterned female Rat Snake.', 'Snazzy is a sleek and stunning two-year-old female Rat Snake with rich, vibrant patterning. She is a very calm snake who is easy to handle and is quite active when exploring her tank. She would make an excellent pet for someone who is ready to move beyond a beginner reptile and appreciate a truly striking serpent.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (9, 2, 9, 'Spoopy', '10 years', '2kg', 'A long, mysterious, and massive Rat Snake.', 'Spoopy is a massive, ten-year-old male Rat Snake. Weighing in at 2kg, he is a substantial and impressive reptile. Despite his imposing size, he is an exceptionally calm snake who is ready to be a quiet, scaly best friend to a dedicated owner. Due to his age and size, he needs an experienced reptile enthusiast.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (9, 2, 2, 'Apollo', '7 months', '10kg', 'A big, handsome young fella with a big appetite.', 'Apollo is a large, handsome seven-month-old male Rat Snake. He is growing fast and has a healthy, robust appetite! He is very easy to handle and enjoys exploring in a controlled environment. He would thrive with an owner who can continue his socialization and appreciates a growing, active snake.')

-- for dog
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (10, 2, 4, 'Puff', '7 years', '10kg', 'A giant, fluffy sled dog who needs space and walks.', 'Puff is a big, friendly seven-year-old male Alaskan Malamute. He’s a true gentle giant, but do not let his name fool you—he is a very substantial dog! He needs a home with lots of space to roam and an owner dedicated to long, consistent daily walks. He is good with older, respectful children but needs to be the only dog in the home.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (10, 1, 9, 'Fluffy', '12 months', '20kg', 'A young, gentle snow dog who is great with kids.', 'Fluffy is a sweet, one-year-old female Alaskan Malamute. She has a wonderfully gentle disposition and is excellent with children of all ages. She absolutely loves cold weather and would adore a home with a yard where she can play in the snow! She is eager to please and ready to learn.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (11, 2, 2, 'Buttercup', '6 years', '50 kg', 'A tiny dog with a big personality and a massive fluff.', 'Buttercup is a sassy six-year-old male Pomeranian. Weighing in at 50kg, he is a substantial, confident dog who is active, vocal, and believes he is royalty. He is looking for a new royal family to shower him with attention, premium treats, and regular grooming to maintain his impressive coat. He’d do best as the star of the show.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (12, 1, 1, 'Gumdrop', '8 months', '30kg', 'A spotty, silly, and sweet Dalmatian puppy needing exercise.', 'Gumdrop is an eight-month-old female Dalmatian puppy. She is a bouncy, playful dog with classic spots and an incredibly sweet, silly nature. Dalmatians are high-energy, so Gumdrop needs an active family dedicated to providing lots of daily exercise, training, and love to help her grow into a wonderful adult companion.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (13, 2, 7, 'Dogzilla', '5 years', '70kg', 'A big personality in a small dog—loyal and confident.', 'Dogzilla is a five-year-old male Chihuahua. Despite his diminutive size, he has a massive, confident personality and is fiercely loyal to his chosen human. He’s happy to be carried and enjoys quiet time on the sofa. He needs an adult-only home where he can be the center of attention and rule his kingdom in peace.')

-- for bird
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (14, 2, 9, 'Gizmo', '3 years', '19g', 'A sweet little chirper who sings beautiful, happy songs.', 'Gizmo is a cheerful, three-year-old male Canary. He is known for his vibrant yellow plumage and his beautiful, happy, and varied songs that he performs daily. He needs a large, engaging cage and a sunny spot in the house to keep him singing. He is an excellent choice for a first-time bird owner.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (14, 1, 9, 'Wylie', '6 years', '13g', 'An experienced, quiet bird who enjoys a calm environment.', 'Wylie is a mature, six-year-old female Canary. She is a gentle, soft-spoken bird who appreciates a calm and predictable environment. She may not sing as loudly as the younger canaries, but her quiet presence is incredibly soothing. She adores seed treats and fresh greens.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (14, 1, 9, 'Kenobi', '16 years', '13.6g', 'The oldest songstress whose gentle chirps bring peace.', 'Kenobi is a truly seasoned canary, an incredible sixteen-year-old female! She is a gentle and well-loved bird whose soft, consistent chirps bring a feeling of peace and longevity to any room. She is a low-maintenance pet perfect for a quiet home that will appreciate her senior status.')
INSERT [dbo].Pet (Breed_ID, Gender_ID, Location_ID, Pet_Name, Pet_Age, Pet_Weight, Pet_Short_Description, Pet_Long_Description) 
VALUES (14, 1, 9, 'Coco', '2 years', '20g', 'A vibrant little singer ready to fill your home with music.', 'Coco is a lively two-year-old female Canary. She is one of our most vocal birds, full of vibrant energy and complex, beautiful songs. She is ready to fill your home with music and is very engaged with her environment. She needs a secure, stimulating cage and plenty of interaction.')


